import logging
import os
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from urllib.parse import unquote

def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')
    
    # Get blob path from query parameters
    blob_path = req.params.get('path')
    
    if not blob_path:
        return func.HttpResponse(
            "Please pass a blob path in the query string",
            status_code=400
        )
    
    # Decode the blob path
    blob_path = unquote(blob_path)
    
    # Validate blob path to prevent directory traversal
    if '..' in blob_path:
        return func.HttpResponse(
            "Invalid blob path",
            status_code=400
        )
    
    # Get storage account connection string from environment
    connection_string = os.environ.get('AzureWebJobsStorage')
    if not connection_string:
        return func.HttpResponse(
            "Storage account connection string not found",
            status_code=500
        )
    
    try:
        # Create blob service client
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        
        # Extract container name and blob name
        parts = blob_path.lstrip('/').split('/', 1)
        if len(parts) < 2:
            return func.HttpResponse(
                "Invalid blob path format",
                status_code=400
            )
        
        container_name = parts[0]
        blob_name = parts[1]
        
        # Get blob client
        blob_client = blob_service_client.get_blob_client(
            container=container_name,
            blob=blob_name
        )
        
        # Read blob content
        blob_data = blob_client.download_blob().readall()
        
        # Get content type
        blob_properties = blob_client.get_blob_properties()
        content_type = blob_properties.content_settings.content_type if blob_properties.content_settings else 'application/octet-stream'
        
        return func.HttpResponse(
            blob_data,
            headers={
                'Content-Type': content_type
            },
            status_code=200
        )
        
    except Exception as e:
        logging.error(f"Error reading blob: {str(e)}")
        return func.HttpResponse(
            "Error reading blob",
            status_code=500
        )